54	static bool match_attr_val(const RTLIL::Const &value, const std::string &pattern, char match_op)
55	{
56		if (match_op == 0)
57			return true;
58	
59		if ((value.flags & RTLIL::CONST_FLAG_STRING) == 0)
60		{
61			RTLIL::SigSpec sig_value;
62	
63			if (!RTLIL::SigSpec::parse(sig_value, nullptr, pattern))
64				return false;
65	
66			RTLIL::Const pattern_value = sig_value.as_const();
67	
68			if (match_op == '=')
69				return value == pattern_value;
70			if (match_op == '!')
71				return value != pattern_value;
72			if (match_op == '<')
73				return value.as_int() < pattern_value.as_int();
74			if (match_op == '>')
75				return value.as_int() > pattern_value.as_int();
76			if (match_op == '[')
77				return value.as_int() <= pattern_value.as_int();
78			if (match_op == ']')
79				return value.as_int() >= pattern_value.as_int();
80		}
81		else
82		{
83			std::string value_str = value.decode_string();
84	
85			if (match_op == '=')
86				if (patmatch(pattern.c_str(), value.decode_string().c_str()))
87					return true;
88	
89			if (match_op == '=')
90				return value_str == pattern;
91			if (match_op == '!')
92				return value_str != pattern;
93			if (match_op == '<')
94				return value_str < pattern;
95			if (match_op == '>')
96				return value_str > pattern;
97			if (match_op == '[')
98				return value_str <= pattern;
99			if (match_op == ']')
100				return value_str >= pattern;
101		}
102	
103		log_abort();
104	}
