127	
128		if (pos != std::string::npos) {
129			if (match_expr.compare(pos, 2, "!=") == 0)
130				return match_attr(attributes, match_expr.substr(0, pos), match_expr.substr(pos+2), '!');
131			if (match_expr.compare(pos, 2, "<=") == 0)
132				return match_attr(attributes, match_expr.substr(0, pos), match_expr.substr(pos+2), '[');
133			if (match_expr.compare(pos, 2, ">=") == 0)
134				return match_attr(attributes, match_expr.substr(0, pos), match_expr.substr(pos+2), ']');
135			return match_attr(attributes, match_expr.substr(0, pos), match_expr.substr(pos+1), match_expr[pos]);
136		}
137	
138		return match_attr(attributes, match_expr, std::string(), 0);
139	}
