159			lhs.clear();
160			return;
161		}
162	
163		if (lhs.selected_modules.size() == 0 && lhs.selected_members.size() == 0) {
164			if (lhs.selects_boxes)
165				lhs.complete_selection = true;
166			else
167				lhs.full_selection = true;
168			return;
169		}
170	
171		auto new_sel = RTLIL::Selection::EmptySelection();
172	
173		for (auto mod : design->modules())
174		{
175			if (!lhs.selects_boxes && mod->get_blackbox_attribute())
176				continue;
177			if (lhs.selected_whole_module(mod->name))
178				continue;
179			if (!lhs.selected_module(mod->name)) {
180				new_sel.selected_modules.insert(mod->name);
181				continue;
182			}
183	
184			for (auto wire : mod->wires())
185				if (!lhs.selected_member(mod->name, wire->name))
186					new_sel.selected_members[mod->name].insert(wire->name);
187			for (auto &it : mod->memories)
