193			for (auto &it : mod->processes)
194				if (!lhs.selected_member(mod->name, it.first))
195					new_sel.selected_members[mod->name].insert(it.first);
196		}
197	
198		lhs.selected_modules.swap(new_sel.selected_modules);
199		lhs.selected_members.swap(new_sel.selected_members);
