686	static void select_stmt(RTLIL::Design *design, std::string arg, bool disable_empty_warning = false)
687	{
688		std::string arg_mod, arg_memb;
689		std::unordered_map<std::string, bool> arg_mod_found;
690		std::unordered_map<std::string, bool> arg_memb_found;
691	
692		auto isprefixed = [](const string &s) {
693			return GetSize(s) >= 2 && ((s[0] >= 'a' && s[0] <= 'z') || (s[0] >= 'A' && s[0] <= 'Z')) && s[1] == ':';
694		};
695	
696		if (arg.size() == 0)
697			return;
698	
699		if (arg[0] == '%') {
700			if (arg == "%") {
701				work_stack.push_back(design->selection());
702			} else
703			if (arg == "%%") {
704				while (work_stack.size() > 1) {
705					select_op_union(design, work_stack.front(), work_stack.back());
706					work_stack.pop_back();
707				}
708			} else
709			if (arg == "%n") {
710				if (work_stack.size() < 1)
711					log_cmd_error("Must have at least one element on the stack for operator %%n.\n");
712				select_op_neg(design, work_stack[work_stack.size()-1]);
713			} else
714			if (arg == "%u") {
715				if (work_stack.size() < 2)
716					log_cmd_error("Must have at least two elements on the stack for operator %%u.\n");
717				select_op_union(design, work_stack[work_stack.size()-2], work_stack[work_stack.size()-1]);
718				work_stack.pop_back();
719			} else
720			if (arg == "%d") {
721				if (work_stack.size() < 2)
722					log_cmd_error("Must have at least two elements on the stack for operator %%d.\n");
723				select_op_diff(design, work_stack[work_stack.size()-2], work_stack[work_stack.size()-1]);
724				work_stack.pop_back();
725			} else
726			if (arg == "%D") {
727				if (work_stack.size() < 2)
728					log_cmd_error("Must have at least two elements on the stack for operator %%D.\n");
729				select_op_diff(design, work_stack[work_stack.size()-1], work_stack[work_stack.size()-2]);
730				work_stack[work_stack.size()-2] = work_stack[work_stack.size()-1];
731				work_stack.pop_back();
732			} else
733			if (arg == "%i") {
734				if (work_stack.size() < 2)
735					log_cmd_error("Must have at least two elements on the stack for operator %%i.\n");
736				select_op_intersect(design, work_stack[work_stack.size()-2], work_stack[work_stack.size()-1]);
737				work_stack.pop_back();
738			} else
739			if (arg.size() >= 2 && arg[0] == '%' && arg[1] == 'R') {
740				if (work_stack.size() < 1)
741					log_cmd_error("Must have at least one element on the stack for operator %%R.\n");
742				int count = arg.size() > 2 ? atoi(arg.c_str() + 2) : 1;
743				select_op_random(design, work_stack[work_stack.size()-1], count);
744			} else
745			if (arg == "%s") {
746				if (work_stack.size() < 1)
747					log_cmd_error("Must have at least one element on the stack for operator %%s.\n");
748				select_op_submod(design, work_stack[work_stack.size()-1]);
749			} else
750			if (arg == "%M") {
751				if (work_stack.size() < 1)
752					log_cmd_error("Must have at least one element on the stack for operator %%M.\n");
753				select_op_cells_to_modules(design, work_stack[work_stack.size()-1]);
754			} else
755			if (arg == "%C") {
756				if (work_stack.size() < 1)
757					log_cmd_error("Must have at least one element on the stack for operator %%C.\n");
758				select_op_module_to_cells(design, work_stack[work_stack.size()-1]);
759			} else
760			if (arg == "%c") {
761				if (work_stack.size() < 1)
762					log_cmd_error("Must have at least one element on the stack for operator %%c.\n");
763				work_stack.push_back(work_stack.back());
764			} else
765			if (arg == "%m") {
766				if (work_stack.size() < 1)
767					log_cmd_error("Must have at least one element on the stack for operator %%m.\n");
768				select_op_fullmod(design, work_stack[work_stack.size()-1]);
769			} else
770			if (arg == "%a") {
771				if (work_stack.size() < 1)
772					log_cmd_error("Must have at least one element on the stack for operator %%a.\n");
773				select_op_alias(design, work_stack[work_stack.size()-1]);
774			} else
775			if (arg == "%x" || (arg.size() > 2 && arg.compare(0, 2, "%x") == 0 && (arg[2] == ':' || arg[2] == '*' || arg[2] == '.' || ('0' <= arg[2] && arg[2] <= '9')))) {
776				if (work_stack.size() < 1)
777					log_cmd_error("Must have at least one element on the stack for operator %%x.\n");
778				select_op_expand(design, arg, 'x', false);
779			} else
780			if (arg == "%ci" || (arg.size() > 3 && arg.compare(0, 3, "%ci") == 0 && (arg[3] == ':' || arg[3] == '*' || arg[3] == '.' || ('0' <= arg[3] && arg[3] <= '9')))) {
781				if (work_stack.size() < 1)
782					log_cmd_error("Must have at least one element on the stack for operator %%ci.\n");
783				select_op_expand(design, arg, 'i', false);
784			} else
785			if (arg == "%co" || (arg.size() > 3 && arg.compare(0, 3, "%co") == 0 && (arg[3] == ':' || arg[3] == '*' || arg[3] == '.' || ('0' <= arg[3] && arg[3] <= '9')))) {
786				if (work_stack.size() < 1)
787					log_cmd_error("Must have at least one element on the stack for operator %%co.\n");
788				select_op_expand(design, arg, 'o', false);
789			} else
790			if (arg == "%xe" || (arg.size() > 3 && arg.compare(0, 3, "%xe") == 0 && (arg[3] == ':' || arg[3] == '*' || arg[3] == '.' || ('0' <= arg[3] && arg[3] <= '9')))) {
791				if (work_stack.size() < 1)
792					log_cmd_error("Must have at least one element on the stack for operator %%xe.\n");
793				select_op_expand(design, arg, 'x', true);
794			} else
795			if (arg == "%cie" || (arg.size() > 4 && arg.compare(0, 4, "%cie") == 0 && (arg[4] == ':' || arg[4] == '*' || arg[4] == '.' || ('0' <= arg[4] && arg[4] <= '9')))) {
796				if (work_stack.size() < 1)
797					log_cmd_error("Must have at least one element on the stack for operator %%cie.\n");
798				select_op_expand(design, arg, 'i', true);
799			} else
800			if (arg == "%coe" || (arg.size() > 4 && arg.compare(0, 4, "%coe") == 0 && (arg[4] == ':' || arg[4] == '*' || arg[4] == '.' || ('0' <= arg[4] && arg[4] <= '9')))) {
801				if (work_stack.size() < 1)
802					log_cmd_error("Must have at least one element on the stack for operator %%coe.\n");
803				select_op_expand(design, arg, 'o', true);
804			} else
805				log_cmd_error("Unknown selection operator '%s'.\n", arg);
806			if (work_stack.size() >= 1)
807				select_filter_active_mod(design, work_stack.back());
808			return;
809		}
810	
811		if (arg[0] == '@') {
812			std::string set_name = RTLIL::escape_id(arg.substr(1));
813			if (design->selection_vars.count(set_name) > 0)
814				work_stack.push_back(design->selection_vars[set_name]);
815			else
816				log_cmd_error("Selection @%s is not defined!\n", RTLIL::unescape_id(set_name));
817			select_filter_active_mod(design, work_stack.back());
818			return;
819		}
820	
821		bool select_blackboxes = false;
822		if (arg.substr(0, 1) == "=") {
823			arg = arg.substr(1);
824			select_blackboxes = true;
825		}
826	
827		if (!design->selected_active_module.empty()) {
828			arg_mod = design->selected_active_module;
829			arg_memb = arg;
830			if (!isprefixed(arg_memb))
831				arg_memb_found[arg_memb] = false;
832		} else
833		if (isprefixed(arg) && arg[0] >= 'a' && arg[0] <= 'z') {
834			arg_mod = "*", arg_memb = arg;
835		} else {
836			size_t pos = arg.find('/');
837			if (pos == std::string::npos) {
838				arg_mod = arg;
839				if (!isprefixed(arg_mod))
840					arg_mod_found[arg_mod] = false;
841			} else {
842				arg_mod = arg.substr(0, pos);
843				if (!isprefixed(arg_mod))
844					arg_mod_found[arg_mod] = false;
845				arg_memb = arg.substr(pos+1);
846				if (!isprefixed(arg_memb))
847					arg_memb_found[arg_memb] = false;
848			}
849		}
850	
851		bool full_selection = (arg == "*" && arg_mod == "*");
852		work_stack.push_back(RTLIL::Selection(full_selection, select_blackboxes, design));
853		RTLIL::Selection &sel = work_stack.back();
854	
855		if (sel.full_selection) {
856			if (sel.selects_boxes) sel.optimize(design);
857			select_filter_active_mod(design, work_stack.back());
858			return;
859		}
860	
861		for (auto mod : design->modules())
862		{
863			if (!select_blackboxes && mod->get_blackbox_attribute())
864				continue;
865	
866			if (arg_mod.compare(0, 2, "A:") == 0) {
867				if (!match_attr(mod->attributes, arg_mod.substr(2)))
868					continue;
869			} else
870			if (arg_mod.compare(0, 2, "N:") == 0) {
871				if (!match_ids(mod->name, arg_mod.substr(2)))
872					continue;
873			} else
874			if (!match_ids(mod->name, arg_mod))
875				continue;
876			else
877				arg_mod_found[arg_mod] = true;
878	
879			if (arg_memb == "") {
880				sel.selected_modules.insert(mod->name);
881				continue;
882			}
883	
884			if (arg_memb.compare(0, 2, "w:") == 0) {
885				for (auto wire : mod->wires())
886					if (match_ids(wire->name, arg_memb.substr(2)))
887						sel.selected_members[mod->name].insert(wire->name);
888			} else
889			if (arg_memb.compare(0, 2, "i:") == 0) {
890				for (auto wire : mod->wires())
891					if (wire->port_input && match_ids(wire->name, arg_memb.substr(2)))
892						sel.selected_members[mod->name].insert(wire->name);
893			} else
894			if (arg_memb.compare(0, 2, "o:") == 0) {
895				for (auto wire : mod->wires())
896					if (wire->port_output && match_ids(wire->name, arg_memb.substr(2)))
897						sel.selected_members[mod->name].insert(wire->name);
898			} else
899			if (arg_memb.compare(0, 2, "x:") == 0) {
900				for (auto wire : mod->wires())
901					if ((wire->port_input || wire->port_output) && match_ids(wire->name, arg_memb.substr(2)))
902						sel.selected_members[mod->name].insert(wire->name);
903			} else
904			if (arg_memb.compare(0, 2, "s:") == 0) {
905				size_t delim = arg_memb.substr(2).find(':');
906				if (delim == std::string::npos) {
907					int width = atoi(arg_memb.substr(2).c_str());
908					for (auto wire : mod->wires())
909						if (wire->width == width)
910							sel.selected_members[mod->name].insert(wire->name);
911				} else {
912					std::string min_str = arg_memb.substr(2, delim);
913					std::string max_str = arg_memb.substr(2+delim+1);
914					int min_width = min_str.empty() ? 0 : atoi(min_str.c_str());
915					int max_width = max_str.empty() ? -1 : atoi(max_str.c_str());
916					for (auto wire : mod->wires())
917						if (min_width <= wire->width && (wire->width <= max_width || max_width == -1))
918							sel.selected_members[mod->name].insert(wire->name);
919				}
920			} else
921			if (arg_memb.compare(0, 2, "m:") == 0) {
922				for (auto &it : mod->memories)
923					if (match_ids(it.first, arg_memb.substr(2)))
924						sel.selected_members[mod->name].insert(it.first);
925			} else
926			if (arg_memb.compare(0, 2, "c:") == 0) {
