1035	void handle_extra_select_args(Pass *pass, const vector<string> &args, size_t argidx, size_t args_size, RTLIL::Design *design)
1036	{
1037		work_stack.clear();
1038		for (; argidx < args_size; argidx++) {
1039			if (args[argidx].compare(0, 1, "-") == 0) {
1040				if (pass != nullptr)
1041					pass->cmd_error(args, argidx, "Unexpected option in selection arguments.");
1042				else
1043					log_cmd_error("Unexpected option in selection arguments.");
1044			}
1045			select_stmt(design, args[argidx]);
1046		}
1047		while (work_stack.size() > 1) {
1048			select_op_union(design, work_stack.front(), work_stack.back());
1049			work_stack.pop_back();
1050		}
1051		if (work_stack.empty())
1052			design->push_empty_selection();
1053		else
1054			design->push_selection(work_stack.back());
1055	}
1056	
1057	// extern decl. in register.h
1058	RTLIL::Selection eval_select_args(const vector<string> &args, RTLIL::Design *design)
1059	{
1060		work_stack.clear();
1061		for (auto &arg : args)
1062			select_stmt(design, arg);
1063		while (work_stack.size() > 1) {
1064			select_op_union(design, work_stack.front(), work_stack.back());
1065			work_stack.pop_back();
1066		}
1067		if (work_stack.empty())
1068			return RTLIL::Selection::EmptySelection(design);
1069		return work_stack.back();
1070	}
