1072	// extern decl. in register.h
1073	void eval_select_op(vector<RTLIL::Selection> &work, const string &op, RTLIL::Design *design)
1074	{
1075		work_stack.swap(work);
1076		select_stmt(design, op);
1077		work_stack.swap(work);
1078	}
